webpackJsonp([0xb4996c11184a],{419:function(t,e){t.exports={data:{site:{siteMetadata:{title:"Josh Kuiros",author:"Josh Kuiros"}},markdownRemark:{id:"/Users/kuiros/code/kuiro5.github.io/src/pages/minimal-vim-markdown-setup/index.md absPath of file >>> MarkdownRemark",html:'<h2>1. Setting Text Width</h2>\n<p>This will create a max text width for markdown files.</p>\n<div class="gatsby-highlight">\n      <pre class="language-text"><code class="language-text"> autocmd BufRead,BufNewFile *.md setlocal textwidth=80</code></pre>\n      </div>\n<h2>2. Setting Autoformat Options</h2>\n<p>This will autoformat options on change.</p>\n<div class="gatsby-highlight">\n      <pre class="language-text"><code class="language-text"> autocmd BufRead,BufNewFile *.md setlocal formatoptions+=t</code></pre>\n      </div>\n<h2>3. Formatting Existing Markdown Files</h2>\n<p>The above settings will work on new files, but what about existing files?</p>\n<div class="gatsby-highlight">\n      <pre class="language-text"><code class="language-text"># highlight the entire file\ngg\ncmd + v\nG\n\n# format\ngQ</code></pre>\n      </div>',frontmatter:{title:"Minimal Vim Markdown Setup",date:"July 03, 2018"}}},pathContext:{slug:"/minimal-vim-markdown-setup/",previous:{fields:{slug:"/programming-variable-casing/"},frontmatter:{title:"Programming Variable Casing"}},next:!1}}}});
